-- Populate latitude/longitude (optimized with temp table)

CREATE TEMP TABLE coords_temp (
	code VARCHAR(12) PRIMARY KEY,
	latitude FLOAT8,
	longitude FLOAT8
) ON COMMIT DROP;

-- Latitude

-- Longitude (upsert for same codes)

UPDATE regions r SET latitude = c.latitude, longitude = c.longitude FROM coords_temp c WHERE r.code = c.code;
